#!/usr/bin/env bun
// Compare 5 btop-inspired Mode 1 designs side by side
// Each design was independently generated by a different AI model

const R = "\x1b[0m";
const B = "\x1b[1m";
const D = "\x1b[2m"; // dim

// Foreground
const green = (s: string) => `\x1b[32m${s}${R}`;
const bgreen = (s: string) => `\x1b[92m${s}${R}`;
const blue = (s: string) => `\x1b[34m${s}${R}`;
const bblue = (s: string) => `\x1b[94m${s}${R}`;
const cyan = (s: string) => `\x1b[36m${s}${R}`;
const yellow = (s: string) => `\x1b[33m${s}${R}`;
const byellow = (s: string) => `\x1b[93m${s}${R}`;
const red = (s: string) => `\x1b[31m${s}${R}`;
const bred = (s: string) => `\x1b[91m${s}${R}`;
const white = (s: string) => `\x1b[97m${s}${R}`;
const gray = (s: string) => `\x1b[90m${s}${R}`;
const bold = (s: string) => `\x1b[1m${s}${R}`;
const magenta = (s: string) => `\x1b[35m${s}${R}`;
const dim = (s: string) => `\x1b[2m${s}${R}`;

// Background
const bgGreen = (s: string) => `\x1b[42m\x1b[30m${s}${R}`;
const bgBlue = (s: string) => `\x1b[44m\x1b[97m${s}${R}`;
const bgAmber = (s: string) => `\x1b[44m\x1b[97m\x1b[1m${s}${R}`;
const bgGray = (s: string) => `\x1b[48;5;238m\x1b[97m${s}${R}`;

const strip = (s: string) => s.replace(/\x1b\[[0-9;]*m/g, "");
const pad = (s: string, w: number) => {
	const vis = strip(s).length;
	return s + " ".repeat(Math.max(0, w - vis));
};

// Latency coloring
const lat = (ms: number): string => {
	const s = `~${ms}ms`;
	if (ms <= 20) return bgreen(s);
	if (ms <= 100) return byellow(s);
	return bred(s);
};

// Gauge bar: proportional to 500ms max, 14 chars wide
const gauge = (ms: number): string => {
	const maxMs = 500;
	const barW = 14;
	const filled = Math.max(1, Math.round((ms / maxMs) * barW));
	const empty = barW - filled;

	// Pick gauge character based on fill fraction
	const blockChars = "▏▎▍▌▋▊▉█";
	const idx = Math.min(
		Math.floor((ms / maxMs) * (blockChars.length - 1)),
		blockChars.length - 1,
	);
	const ch = blockChars[idx];

	let color: (s: string) => string;
	if (ms <= 20) color = bgreen;
	else if (ms <= 100) color = byellow;
	else color = bred;

	// For small values, just show the fractional block char
	if (filled <= 1) {
		return color(ch) + dim("░".repeat(empty));
	}
	return color("█".repeat(filled - 1) + ch) + dim("░".repeat(empty));
};

// Separator between designs
function separator(title: string, model: string) {
	console.log();
	console.log(bold(`  ${"═".repeat(65)}`));
	console.log(bold(`  DESIGN ${title}`) + `  ${gray(`by ${model}`)}`);
	console.log(bold(`  ${"═".repeat(65)}`));
}

