// DESIGN A: Internal (Claude) — Per-step rounded sub-boxes + model wings
// ═══════════════════════════════════════════════════════════════════
function designA() {
	separator("A", "Internal Claude");
	const W = 61;
	const o = (s: string) => {
		console.log(`  │ ${pad(s, W)} │`);
	};

	// Helpers for sub-boxes
	const subTop = (name: string, extra = "") => {
		const label = ` ${name} `;
		const trail = extra ? ` ${extra} ` : "";
		const fill = 42 - label.length - trail.length;
		return bold(`╭─${label}${"─".repeat(Math.max(0, fill))}${trail}╮`);
	};
	const subBot = () => bold("╰" + "─".repeat(42) + "╯");
	const subLine = (content: string) => {
		return bold("│") + `  ${pad(content, 39)}` + bold("│");
	};

	// Model wing box (dim, appears to the right)
	const wingTop = dim("╭────────╮");
	const wingBot = dim("╰────────╯");
	const wingLine = (l1: string, l2: string) =>
		dim("│") + ` ${bgAmber(` ${l1} `)} ` + dim("│");
	const wingAuto = dim("│") + ` ${dim("auto")}   ` + dim("│");

	console.log();
	console.log(
		`  ${bold("MODE 1: LOCAL")}  ${dim("everything on your machine")}`,
	);
	console.log();
	console.log(
		`  ╭─ ${bold(white("mnemex pipeline"))} ${"─".repeat(W - 22)}╮`,
	);
	o("");
	o(dim("source files"));
	o("     │");

	// parse
	o(`${subTop("parse")}           `);
	o(
		`${subLine(`tree-sitter AST          ${bgreen("▏")} ${dim("~5ms  CPU")}`)}           `,
	);
	o(`${subBot()}           `);
	o(`     │ ${dim("text chunks")}`);
	o("     ▼");

	// embed + wing
	o(`${subTop("embed")}  ${wingTop} `);
	o(
		`${subLine(`vectorise chunks         ${byellow("▍")} ${dim("~30ms GPU")}`)}  ${wingLine("embed", "model")} `,
	);
	o(`${subBot()}  ${dim("│")} ${bgAmber(" model ")}  ${dim("│")} `);
	o(`     │ ${dim("vectors")}                   ${dim("◄──────")}${wingAuto} `);
	o(`     ▼                               ${wingBot} `);

	// index
	o(`${subTop("index")}           `);
	o(
		`${subLine(`LanceDB local store      ${bgreen("▏")} ${dim("~5ms  disk")}`)}           `,
	);
	o(`${subBot()}           `);
	o(`     │ ${dim("candidates")}`);
	o("     ▼");

	// search
	o(`${subTop("search")}           `);
	o(
		`${subLine(`vector + BM25 hybrid     ${bgreen("▎")} ${dim("~15ms CPU")}`)}           `,
	);
	o(`${subBot()}           `);
	o(`     │ ${dim("top-K results")}`);
	o("     ▼");

	// rerank + wing
	o(`${subTop("rerank")}  ${wingTop} `);
	o(
		`${subLine(`LLM re-scores results    ${byellow("▌")} ${dim("~100ms GPU")}`)}  ${dim("│")} ${bgAmber(" LLM ")}   ${dim("│")} `,
	);
	o(`${subBot()}  ${dim("│")} ${bgAmber(" model ")}  ${dim("│")} `);
	o(`     │ ${dim("scored results")}            ${dim("◄──────")}${wingAuto} `);
	o(`     ▼                               ${wingBot} `);

	// enrich
	o(`${subTop("enrich", "optional")}          `);
	o(
		`${subLine(`code summaries (same LLM) ${bred("█░")} ${dim("~500ms GPU")}`)}          `,
	);
	o(`${subBot()}           `);
	o(`     │ ${dim("enriched results")}`);
	o("     ▼");
	o(bgreen("results"));
	o("");
	o(`${dim("via Ollama or LM Studio")}    ${bgreen("● zero bytes leave")}`);
	console.log(`  ╰${"─".repeat(W + 2)}╯`);
	console.log();

	// Tech summary
	console.log(dim(`  ${"┄".repeat(59)}`));
	console.log(`  ${bgGray(" Tech Summary ")}  ${bold("Local Mode")}`);
	console.log(
		`  ${green("●")} Runtime     ${white("Ollama or LM Studio (local)")}`,
	);
	console.log(
		`  ${green("●")} Storage     ${white("LanceDB (~50 MB per 10K files)")}`,
	);
	console.log(
		`  ${green("●")} Embedding   ${byellow("auto-detected")} ${dim("e.g. nomic-embed-text 274 MB")}`,
	);
	console.log(
		`  ${green("●")} Rerank      ${byellow("auto-detected")} ${dim("e.g. llama3 8B, 4.7 GB")}`,
	);
	console.log(
		`  ${green("●")} Enrich      ${byellow("same LLM")} ${dim("code summaries, optional")}`,
	);
	console.log(
		`  ${green("●")} Privacy     ${bgreen("air-gapped — zero bytes leave machine")}`,
	);
	console.log(
		`  ${green("●")} Requires    ${white("Apple Silicon or NVIDIA GPU, ≥16 GB RAM")}`,
	);
	console.log();

	// Latency table with gauge bars
	console.log(dim(`  Step     Latency   Gauge          Note`));
	console.log(dim(`  ──────── ───────── ────────────── ────────────────────`));
	console.log(`  parse    ${pad(lat(5), 10)}${gauge(5)}  tree-sitter (CPU)`);
	console.log(`  embed    ${pad(lat(30), 10)}${gauge(30)}  embed model (GPU)`);
	console.log(`  index    ${pad(lat(5), 10)}${gauge(5)}  LanceDB write (disk)`);
	console.log(
		`  search   ${pad(lat(15), 10)}${gauge(15)}  vector + BM25 (CPU)`,
	);
	console.log(
		`  rerank   ${pad(lat(100), 10)}${gauge(100)}  LLM scoring (GPU)`,
	);
	console.log(
		`  enrich   ${pad(lat(500), 10)}${gauge(500)}  LLM summaries (optional)`,
	);
	console.log(dim(`  ─────────────────────────────────────────────────────`));
	console.log(
		`  ${bold("search")}   ${pad(lat(130), 10)}search + rerank (no enrich)`,
	);
	console.log(`  ${bold("full")}     ${pad(lat(630), 10)}all steps end-to-end`);
	console.log(dim(`  approximate — depends on hardware and model size`));
}

